let scheduled = false;
let lastY = 0;

function onScroll(): void {
  lastY = window.scrollY;
  if (scheduled) return;
  scheduled = true;
  requestAnimationFrame(() => {
    scheduled = false;
    updateHeaderForScroll(lastY);
  });
}

window.addEventListener('scroll', onScroll, { passive: true });

