// Confirm by mounting/unmounting in a loop and checking heap snapshots/listener counts return to baseline.

import { describe, it, expect } from 'vitest';
it('does not leak listeners or heap across repeated mount/unmount', async () => {
  const before = await heapUsed();
  for (let i = 0; i < 200; i++) { const app = mountComponent(); app.unmount(); }
  global.gc?.();
  expect(listenerCount(window, 'resize')).toBe(0);
  expect(await heapUsed() - before).toBeLessThan(2 * 1024 * 1024);
});

